    if a_acc > 2147483647_u32 {
        check world.out.write("error\n")
        return
    }
    let mut a_val: i32 = a_acc as i32
    if a_neg {
        a_val = 0_i32 - a_val
    }

    // ---- Parse b as i32 from trimmed ASCII digits ----
    let b_n = std.mem.len(b_s)
    let mut b_i: usize = 0
    let mut b_skip_flag: Bool = true
    while b_skip_flag {
