    let mut b_have_digit: Bool = false
    let mut b_acc: u32 = 0_u32
    let mut b_digit_flag: Bool = true
    while b_digit_flag {
        if b_i >= b_n {
            b_digit_flag = false
        } else {
            let c = b_s[b_i]
            if c >= 48_u8 {
                if c <= 57_u8 {
