    let mut b_tail_ok: Bool = true
    while b_tail_flag {
        if b_i >= b_n {
            b_tail_flag = false
        } else {
            let c = b_s[b_i]
            if c == 32_u8 {
                b_i = b_i + 1
            } else {
                if c == 9_u8 {
                    b_i = b_i + 1
                } else {
                    if c == 10_u8 {
                        b_i = b_i + 1
