                } else {
                    envelope[env_n] = c
                    env_n = env_n + 1
                    ui = ui + 1
                }
            }
        }
    }
    envelope[env_n] = 10_u8
    env_n = env_n + 1

    let ct = std.mem.span("Content-Type: application/json\n")
    let ct_n = std.mem.len(ct)
    let mut ci: usize = 0
    while ci < ct_n {
        envelope[env_n] = ct[ci]
        env_n = env_n + 1
        ci = ci + 1
    }
    envelope[env_n] = 10_u8
    env_n = env_n + 1

